const express = require('express');
const projectsRoutes = require('./modules/projects/routes');
const membersRoutes = require('./modules/members/routes');
tasksRoutes = require('./modules/tasks/routes');
commentsRoutes = require('./modules/comments/routes');

const app = express();
app.use(express.json());

app.get('/health', (req, res) => {
  res.json({ ok: true });
});

app.use('/projects', projectsRoutes);
app.use('/projects/:projectId/members', membersRoutes);
app.use('/projects/:projectId/tasks', tasksRoutes);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRoutes);

module.exports = app;

const sendError = (res, status, code, message) => {
  res.status(status).json({ error: { code, message } });
};

module.exports = { sendError };

const express = require('express');
const service = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', (req, res) => {
  const projects = service.getAllProjects();
  res.json({ projects });
});

router.post('/', (req, res) => {
  const { name } = req.body;
  if (!name) {
    return sendError(res, 400, 'INVALID_NAME', 'Name is required');
  }
  const project = service.createProject(name);
  res.status(201).json({ project });
});

module.exports = router;

const { randomUUID } = require('node:crypto');

let projects = {};

const getAllProjects = () => {
  return Object.values(projects);
};

const createProject = (name) => {
  const projectId = randomUUID();
  const project = { id: projectId, name, members: [], tasks: [] };
  projects[projectId] = project;
  return project;
};

module.exports = { getAllProjects, createProject };

const express = require('express');
const service = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', (req, res) => {
  const projectId = req.params.projectId;
  const { userId, role } = req.body;
  if (!userId || !role) {
    return sendError(res, 400, 'INVALID_BODY', 'UserId and role are required');
  }
  const member = service.addMember(projectId, userId, role);
  if (!member) {
    return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
  }
  res.status(201).json({ member });
});

module.exports = router;

const projectsService = require('../projects/service');
const { randomUUID } = require('node:crypto');

const addMember = (projectId, userId, role) => {
  const project = projectsService.getAllProjects().find(p => p.id === projectId);
  if (!project) {
    return null;
  }
  const member = { id: randomUUID(), userId, role };
  project.members.push(member);
  return member;
};

module.exports = { addMember };

const express = require('express');
const service = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', (req, res) => {
  const projectId = req.params.projectId;
  const tasks = service.getTasks(projectId);
  if (!tasks) {
    return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
  }
  const statusFilter = req.query.status;
  const filteredTasks = statusFilter ? tasks.filter(task => task.status === statusFilter) : tasks;
  res.json({ tasks: filteredTasks });
});

router.post('/', (req, res) => {
  const projectId = req.params.projectId;
  const { name } = req.body;
  if (!name) {
    return sendError(res, 400, 'INVALID_NAME', 'Name is required');
  }
  const task = service.createTask(projectId, name);
  if (!task) {
    return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
  }
  res.status(201).json({ task });
});

router.patch('/:taskId', (req, res) => {
  const projectId = req.params.projectId;
  const taskId = req.params.taskId;
  const { status } = req.body;
  if (!status || !['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'INVALID_STATUS', 'Status must be todo or done');
  }
  const task = service.updateTask(projectId, taskId, status);
  if (!task) {
    return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
  }
  res.json({ task });
});

module.exports = router;

const projectsService = require('../projects/service');
const { randomUUID } = require('node:crypto');

const getTasks = (projectId) => {
  const project = projectsService.getAllProjects().find(p => p.id === projectId);
  return project ? project.tasks : null;
};

const createTask = (projectId, name) => {
  const project = projectsService.getAllProjects().find(p => p.id === projectId);
  if (!project) {
    return null;
  }
  const task = { id: randomUUID(), name, status: 'todo' };
  project.tasks.push(task);
  return task;
};

const updateTask = (projectId, taskId, status) => {
  const tasks = getTasks(projectId);
  if (!tasks) {
    return null;
  }
  const task = tasks.find(t => t.id === taskId);
  if (!task) {
    return null;
  }
  task.status = status;
  return task;
};

module.exports = { getTasks, createTask, updateTask };

const express = require('express');
const service = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', (req, res) => {
  const projectId = req.params.projectId;
  const taskId = req.params.taskId;
  const comments = service.getComments(projectId, taskId);
  if (!comments) {
    return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
  }
  res.json({ comments });
});

router.post('/', (req, res) => {
  const projectId = req.params.projectId;
  const taskId = req.params.taskId;
  const { message } = req.body;
  if (!message) {
    return sendError(res, 400, 'INVALID_MESSAGE', 'Message is required');
  }
  const comment = service.addComment(projectId, taskId, message);
  if (!comment) {
    return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
  }
  res.status(201).json({ comment });
});

module.exports = router;

const projectsService = require('../projects/service');
const { randomUUID } = require('node:crypto');

const getComments = (projectId, taskId) => {
  const project = projectsService.getAllProjects().find(p => p.id === projectId);
  if (!project) {
    return null;
  }
  const task = project.tasks.find(t => t.id === taskId);
  return task ? task.comments || [] : null;
};

const addComment = (projectId, taskId, message) => {
  const project = projectsService.getAllProjects().find(p => p.id === projectId);
  if (!project) {
    return null;
  }
  const task = project.tasks.find(t => t.id === taskId);
  if (!task) {
    return null;
  }
  const comment = { id: randomUUID(), message };
  if (!task.comments) {
    task.comments = [];
  }
  task.comments.push(comment);
  return comment;
};

module.exports = { getComments, addComment };
